// Java 22 - unnamed variables
// Learn: Use _ when a value is intentionally discarded.
String[] raw = {"42", "bad"};
int seen = 0;
// _ discards each loop value and cannot be read.
for (String _ : raw) {
  seen++;
}

try {
  Integer.parseInt("bad");
} catch (NumberFormatException _) {
  seen = -1;
}
